 49	// NewPreClaimDecompositionHook dispatches an orchestrator splitter for beads
 50	// that readiness classifies as too_large without returning concrete children.
 51	// It returns a lossless split proposal; the execute loop owns validation,
 52	// child creation, dependency wiring, and fallback behavior.
 53	func NewPreClaimDecompositionHook(store ExecuteBeadLoopStore, runner AgentRunner, rcfg config.ResolvedConfig, projectRoot string) func(context.Context, string) (*PreClaimDecomposition, error) {
 54		return func(ctx context.Context, beadID string) (*PreClaimDecomposition, error) {
 55			return runPreClaimDecomposer(ctx, store, runner, rcfg, projectRoot, beadID)
 56		}
 57	}
