 59	func runPreClaimDecomposer(ctx context.Context, store ExecuteBeadLoopStore, runner AgentRunner, rcfg config.ResolvedConfig, projectRoot string, beadID string) (*PreClaimDecomposition, error) {
 60		tctx, cancel := context.WithTimeout(ctx, decomposerDefaultTimeout)
 61		defer cancel()
 62	
 63		b, err := store.Get(ctx, beadID)
 64		if err != nil {
 65			return nil, fmt.Errorf("decomposer: load bead: %w", err)
 66		}
 67		prompt, err := buildPreClaimDecomposerPrompt(store, b)
 68		if err != nil {
 69			return nil, err
 70		}
 71		runtime := decomposerRuntime(tctx, projectRoot, runner, rcfg)
 72		runtime.Prompt = prompt
 73		runtime.PromptSource = preClaimDecomposerPromptSource
 74		result, err := dispatchLifecycleRun(tctx, projectRoot, nil, runner, rcfg, runtime)
 75		if err != nil {
 76			if tctx.Err() != nil {
 77				return nil, tctx.Err()
 78			}
 79			reason := fmt.Sprintf("dispatch error: %s", err.Error())
 80			if fallback, fallbackErr := fallbackPreClaimDecomposition(b, reason); fallbackErr == nil {
 81				appendPreClaimDecomposeEvent(store, b.ID, nil, rcfg, reason)
 82				return fallback, nil
 83			}
 84			return nil, fmt.Errorf("decomposer: dispatch: %w", err)
 85		}
 86		output := strings.TrimSpace(result.CondensedOutput)
 87		if output == "" {
 88			output = strings.TrimSpace(result.Output)
 89		}
 90		if output == "" {
 91			reason := "empty output"
 92			if fallback, fallbackErr := fallbackPreClaimDecomposition(b, reason); fallbackErr == nil {
 93				appendPreClaimDecomposeEvent(store, b.ID, result, rcfg, reason)
 94				return fallback, nil
 95			}
 96			return nil, fmt.Errorf("decomposer: empty output")
 97		}
 98		decomp, ok := parsePreClaimDecompositionOutput(output)
 99		if !ok {
100			reason := "invalid output"
101			if fallback, fallbackErr := fallbackPreClaimDecomposition(b, reason); fallbackErr == nil {
102				appendPreClaimDecomposeEvent(store, b.ID, result, rcfg, reason)
103				return fallback, nil
104			}
105			return nil, fmt.Errorf("decomposer: invalid output")
106		}
107		if err := validatePreClaimDecomposition(decomp); err != nil {
108			reason := err.Error()
109			if fallback, fallbackErr := fallbackPreClaimDecomposition(b, reason); fallbackErr == nil {
110				appendPreClaimDecomposeEvent(store, b.ID, result, rcfg, reason)
111				return fallback, nil
112			}
113			return nil, err
114		}
115		appendPreClaimDecomposeEvent(store, b.ID, result, rcfg, "")
116		return decomp, nil
117	}
