119	// NewDecomposePostLadderExhaustionHook creates a PostLadderExhaustionHook that
120	// dispatches runDecomposer for TooLarge failure class.
121	func NewDecomposePostLadderExhaustionHook(store ExecuteBeadLoopStore, runner AgentRunner, rcfg config.ResolvedConfig, projectRoot string) PostLadderExhaustionHook {
122		return func(ctx context.Context, beadID string, failureClass RecoveryFailureClass) (*PostLadderExhaustionResult, error) {
123			if failureClass != TooLarge {
124				return &PostLadderExhaustionResult{Attempted: false}, nil
125			}
126			result := runDecomposer(ctx, store, runner, rcfg, projectRoot, beadID)
127			if result.Failed {
128				return &PostLadderExhaustionResult{
129					Attempted: true,
130					Succeeded: false,
131					Path:      Decompose,
132					CostUSD:   result.CostUSD,
133				}, nil
134			}
135			return &PostLadderExhaustionResult{
136				Attempted: true,
137				Succeeded: true,
138				Path:      Decompose,
139				CostUSD:   result.CostUSD,
140			}, nil
141		}
142	}
