144	// runDecomposer dispatches a smart+ powerClass agent to split the bead into child
145	// beads after the escalation ladder has been exhausted. On success, child beads
146	// are created with Parent=beadID, the parent is closed through the store's
147	// lifecycle API, and a "decompose-applied" event is emitted. On failure a
148	// DecomposeResult with Failed=true is returned.
149	func runDecomposer(ctx context.Context, store ExecuteBeadLoopStore, runner AgentRunner, rcfg config.ResolvedConfig, projectRoot string, beadID string) DecomposeResult {
150		tctx, cancel := context.WithTimeout(ctx, decomposerDefaultTimeout)
151		defer cancel()
152	
153		b, err := store.Get(ctx, beadID)
154		if err != nil {
155			return DecomposeResult{Failed: true, Reason: "store_error"}
156		}
157	
158		prompt, err := buildDecomposerPrompt(store, b)
159		if err != nil {
160			return DecomposeResult{Failed: true, Reason: "prompt_error"}
161		}
162	
163		runtime := decomposerRuntime(tctx, projectRoot, runner, rcfg)
164		runtime.Prompt = prompt
165		runtime.PromptSource = decomposerPromptSource
166	
167		result, err := dispatchLifecycleRun(tctx, projectRoot, nil, runner, rcfg, runtime)
168		if err != nil && result == nil {
169			if tctx.Err() != nil {
170				return DecomposeResult{Failed: true, Reason: "timeout"}
171			}
172			return DecomposeResult{Failed: true, Reason: "dispatch_error"}
173		}
174	
175		output := strings.TrimSpace(result.CondensedOutput)
176		if output == "" {
177			output = strings.TrimSpace(result.Output)
178		}
179		if output == "" {
180			return DecomposeResult{Failed: true, Reason: "empty_output", CostUSD: result.CostUSD}
181		}
182	
183		children, ok := parseDecomposerOutput(output)
184		if !ok {
185			return DecomposeResult{Failed: true, Reason: "invalid_output", CostUSD: result.CostUSD}
186		}
187	
188		if len(children) < 1 || len(children) > 5 {
189			return DecomposeResult{Failed: true, Reason: "invalid_count", CostUSD: result.CostUSD}
190		}
191	
192		for _, child := range children {
193			if strings.TrimSpace(child.Title) == "" ||
194				strings.TrimSpace(child.Description) == "" ||
195				strings.TrimSpace(child.Acceptance) == "" {
196				return DecomposeResult{Failed: true, Reason: "malformed_child", CostUSD: result.CostUSD}
197			}
198		}
199	
200		childIDs := make([]string, 0, len(children))
201		for _, child := range children {
202			nb := &bead.Bead{
203				Title:       strings.TrimSpace(child.Title),
204				Description: strings.TrimSpace(child.Description),
205				Acceptance:  strings.TrimSpace(child.Acceptance),
206				Labels:      append([]string(nil), child.Labels...),
207				Parent:      beadID,
208			}
209			if err := store.Create(context.Background(), nb); err != nil {
210				return DecomposeResult{Failed: true, Reason: "create_error"}
211			}
212			childIDs = append(childIDs, nb.ID)
213		}
214	
215		if err := closeDecomposedParent(store, beadID); err != nil {
216			return DecomposeResult{Failed: true, Reason: "close_error", CostUSD: result.CostUSD}
217		}
218	
219		body, _ := json.Marshal(decomposerEventBodyForResult(childIDs, result, rcfg, ""))
220		_ = store.AppendEvent(beadID, bead.BeadEvent{
221			Kind:      "decompose-applied",
222			Summary:   fmt.Sprintf("decomposed into %s", strings.Join(childIDs, ", ")),
223			Body:      string(body),
224			Actor:     "ddx work",
225			Source:    "ddx work",
226			CreatedAt: time.Now().UTC(),
227		})
228	
229		return DecomposeResult{
230			Failed:   false,
231			ChildIDs: childIDs,
232			CostUSD:  result.CostUSD,
233		}
234	}
