236	func closeDecomposedParent(store ExecuteBeadLoopStore, beadID string) error {
237		if err := store.UpdateWithLifecycleStatus(beadID, bead.StatusClosed, bead.LifecycleTransitionOptions{
238			ManualClose: true,
239			Reason:      "post-attempt decomposition complete",
240			Source:      "ddx work",
241		}, func(b *bead.Bead) error {
242			clearReviewTriageClaimMetadata(b)
243			return nil
244		}); err != nil {
245			return err
246		}
247	
248		closer, ok := store.(interface {
249			Close(context.Context, string) error
250		})
251		if !ok {
252			return fmt.Errorf("decomposer: close unsupported")
253		}
254		if err := closer.Close(context.Background(), beadID); err != nil {
255			return err
256		}
257		return nil
258	}
