5233	// nextCandidate returns the next claimable bead from the execution-ready
5234	// queue along with the list of higher-priority beads it skipped (and the
5235	// reason for each skip). The returned skips slice is only meaningful when
5236	// ok=true: it contains every entry that came BEFORE the chosen candidate
5237	// in the priority-sorted ReadyExecution result.
5238	//
5239	// It delegates filter+sort to PreviewQueue and then additionally filters out
5240	// beads already present in the current drain results slice (which is
5241	// non-deterministic across runs and therefore excluded from the stable
5242	// PreviewQueue surface).
5243	func (w *ExecuteBeadWorker) nextCandidate(ctx context.Context, results []ExecuteBeadReport, guards []work.Guard, labelFilter, targetBeadID string) (bead.Bead, []pickerSkip, bool, error) {
5244		// Use PreviewQueue for the stable filter+sort logic. Limit=0 returns all
5245		// entries so we can scan for the first candidate not already present in
5246		// the current drain results slice.
5247		entries, err := PreviewQueue(w.Store, PickerFilters{LabelFilter: labelFilter}, 0)
5248		if err != nil {
5249			return bead.Bead{}, nil, false, err
5250		}
5251	
5252		// Rebuild the ready list from the preview entries in picker order so we
5253		// can apply the per-run drain results slice on top. We need the original
5254		// bead values for the return; fetch them from ReadyExecution (already
5255		// ordered).
5256		ready, err := w.Store.ReadyExecution()
5257		if err != nil {
5258			return bead.Bead{}, nil, false, err
5259		}
5260		// Index by ID for O(1) lookup.
5261		byID := make(map[string]bead.Bead, len(ready))
5262		for _, b := range ready {
5263			byID[b.ID] = b
5264		}
